type Iterator struct {
	// blobValueFetcher is the ValueFetcher to use when retrieving values stored
	// externally in blob files.
	blobValueFetcher blob.ValueFetcher
	// combinedBlobMapping chains the version's BlobFileSet with any blob files
	// from flushable ingests that haven't been flushed yet. This allows initializing
	// blob value fetcher for reading blob values from ingested sstables before they
	// are flushed to the LSM. Populated when there are blob files in either the
	// version's BlobFileSet or flushable ingests.
	combinedBlobMapping combinedBlobFileMapping

	// closeChecker detects double Close. It is intentionally above
	// clearForReuseBoundary so the "closed" bit survives clearForReuse and
	// catches a second Close on the same Iterator pointer. It is reset to the
	// zero value when an Iterator is re-initialized for a new caller (the
	// pool-allocation sites all use a `*dbi = Iterator{...}` literal or
	// explicitly reset it). The `invariants:"reused"` tag exempts it from
	// iterAlloc.assertZeroed.
	closeChecker invariants.CloseChecker `invariants:"reused"`

	// All fields below this field are cleared during Iterator.Close before
	// returning the Iterator to the pool. Any fields above this field must also
	// be cleared, but may be cleared as a part of the body of Iterator.Close
	// (eg, if these types have their own Close method that zeroes their
	// fields).
	clearForReuseBoundary struct{}

	// The context is stored here since (a) Iterators are expected to be
	// short-lived (since they pin memtables and sstables), (b) plumbing a
	// context into every method is very painful, (c) they do not (yet) respect
	// context cancellation and are only used for tracing.
